            sh:resultMessage "value must be a resolvable URL, but we aren't testing to see if the URL resolves..... Can't get xsd:anyURI to work with JSON Schema validation..." ;
            sh:resultPath schema1:url ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:PatternConstraintComponent ;
